module RefModule (  
    input wire clk,  
    input wire reset,  
    input wire in,  
    output reg out  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            out <= 1'b0;  
        else  
            out <= in ^ out;  
    end  
endmodule
